import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface Animal {
  id: number;
  identificador_unico: string;
  nombre: string;
  sexo: string;
  categoria: string;
  estado: string;
  raza_nombre: string;
  ubicacion_nombre: string;
  fecha_nacimiento: string;
}

interface AnimalDetail extends Animal {
  peso_nacimiento: number;
  madre_id: number;
  padre_id: number;
  raza_id: number;
  ubicacion_actual_id: number;
  observaciones: string;
}

const Animals: React.FC = () => {
  const [animals, setAnimals] = useState<Animal[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [showDetail, setShowDetail] = useState<number | null>(null);
  const [animalDetail, setAnimalDetail] = useState<AnimalDetail | null>(null);
  const [formData, setFormData] = useState({
    identificador_unico: '',
    nombre: '',
    sexo: 'hembra',
    categoria: 'lechon',
    fecha_nacimiento: '',
    peso_nacimiento: '',
    observaciones: ''
  });

  useEffect(() => {
    loadAnimals();
  }, []);

  const loadAnimals = async () => {
    try {
      const response = await api.get('/animals');
      setAnimals(response.data);
    } catch (error) {
      console.error('Error cargando animales:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (editingId) {
        await api.put(`/animals/${editingId}`, formData);
      } else {
        await api.post('/animals', formData);
      }
      resetForm();
      loadAnimals();
    } catch (error) {
      console.error('Error guardando animal:', error);
      alert('Error guardando animal');
    }
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({
      identificador_unico: '',
      nombre: '',
      sexo: 'hembra',
      categoria: 'lechon',
      fecha_nacimiento: '',
      peso_nacimiento: '',
      observaciones: ''
    });
  };

  const handleEdit = async (id: number) => {
    try {
      const response = await api.get(`/animals/${id}`);
      const animal = response.data;
      setFormData({
        identificador_unico: animal.identificador_unico,
        nombre: animal.nombre || '',
        sexo: animal.sexo,
        categoria: animal.categoria,
        fecha_nacimiento: animal.fecha_nacimiento || '',
        peso_nacimiento: animal.peso_nacimiento || '',
        observaciones: animal.observaciones || ''
      });
      setEditingId(id);
      setShowForm(true);
    } catch (error) {
      console.error('Error cargando animal:', error);
    }
  };

  const handleView = async (id: number) => {
    try {
      const response = await api.get(`/animals/${id}`);
      setAnimalDetail(response.data);
      setShowDetail(id);
    } catch (error) {
      console.error('Error cargando detalles:', error);
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm('¿Estás seguro de eliminar este animal?')) {
      try {
        await api.delete(`/animals/${id}`);
        loadAnimals();
      } catch (error) {
        console.error('Error eliminando animal:', error);
        alert('Error eliminando animal');
      }
    }
  };

  if (loading) return (
    <div className="loading">
      <div className="loading-spinner"></div>
      <p>Cargando animales...</p>
    </div>
  );

  return (
    <div className="fade-in">
      <div className="card-header">
        <div>
          <h1 className="card-title">🐷 Gestión de Animales</h1>
          <p style={{ color: '#7f8c8d', margin: 0 }}>Control completo del inventario animal</p>
        </div>
        <button 
          className="btn btn-primary"
          onClick={() => {
            if (showForm) {
              resetForm();
            } else {
              setShowForm(true);
            }
          }}
        >
          {showForm ? '❌ Cancelar' : '➕ Nuevo Animal'}
        </button>
      </div>

      {showForm && (
        <div className="card mb-4 fade-in">
          <div className="card-header">
            <h3 className="card-title">
              {editingId ? '✏️ Editar Animal' : '➕ Registrar Nuevo Animal'}
            </h3>
          </div>
          <form onSubmit={handleSubmit}>
            <div className="grid grid-2">
              <div className="form-group">
                <label>Identificador Único:</label>
                <input
                  type="text"
                  className="form-control"
                  value={formData.identificador_unico}
                  onChange={(e) => setFormData({...formData, identificador_unico: e.target.value})}
                  required
                />
              </div>
              <div className="form-group">
                <label>Nombre:</label>
                <input
                  type="text"
                  className="form-control"
                  value={formData.nombre}
                  onChange={(e) => setFormData({...formData, nombre: e.target.value})}
                />
              </div>
              <div className="form-group">
                <label>Sexo:</label>
                <select
                  className="form-control"
                  value={formData.sexo}
                  onChange={(e) => setFormData({...formData, sexo: e.target.value})}
                >
                  <option value="hembra">Hembra</option>
                  <option value="macho">Macho</option>
                </select>
              </div>
              <div className="form-group">
                <label>Categoría:</label>
                <select
                  className="form-control"
                  value={formData.categoria}
                  onChange={(e) => setFormData({...formData, categoria: e.target.value})}
                >
                  <option value="lechon">Lechón</option>
                  <option value="recria">Recría</option>
                  <option value="desarrollo">Desarrollo</option>
                  <option value="engorde">Engorde</option>
                  <option value="reproductor">Reproductor</option>
                </select>
              </div>
              <div className="form-group">
                <label>Fecha de Nacimiento:</label>
                <input
                  type="date"
                  className="form-control"
                  value={formData.fecha_nacimiento}
                  onChange={(e) => setFormData({...formData, fecha_nacimiento: e.target.value})}
                />
              </div>
              <div className="form-group">
                <label>Peso Nacimiento (kg):</label>
                <input
                  type="number"
                  step="0.1"
                  className="form-control"
                  value={formData.peso_nacimiento}
                  onChange={(e) => setFormData({...formData, peso_nacimiento: e.target.value})}
                />
              </div>
              <div className="form-group">
                <label>Observaciones:</label>
                <textarea
                  className="form-control"
                  rows={3}
                  value={formData.observaciones}
                  onChange={(e) => setFormData({...formData, observaciones: e.target.value})}
                />
              </div>
            </div>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button type="submit" className="btn btn-success">
                {editingId ? '💾 Actualizar' : '💾 Guardar'} Animal
              </button>
              <button type="button" className="btn btn-secondary" onClick={resetForm}>
                ❌ Cancelar
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="card">
        <div className="card-header">
          <h3 className="card-title">📋 Lista de Animales ({animals.length})</h3>
          <div className="badge badge-info">{animals.length} registros</div>
        </div>
        {animals.length > 0 ? (
          <div className="table-container">
            <table className="table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Nombre</th>
                <th>Sexo</th>
                <th>Categoría</th>
                <th>Estado</th>
                <th>Raza</th>
                <th>Ubicación</th>
                <th>Nacimiento</th>
                <th>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {animals.map(animal => (
                <tr key={animal.id}>
                  <td>{animal.identificador_unico}</td>
                  <td>{animal.nombre || '-'}</td>
                  <td>
                    <span className="badge" style={{
                      backgroundColor: animal.sexo === 'hembra' ? '#e91e63' : '#2196f3',
                      color: 'white'
                    }}>
                      {animal.sexo === 'hembra' ? '♀ Hembra' : '♂ Macho'}
                    </span>
                  </td>
                  <td>
                    <span className="badge badge-info" style={{ textTransform: 'capitalize' }}>
                      {animal.categoria}
                    </span>
                  </td>
                  <td>
                    <span className={`badge ${
                      animal.estado === 'activo' ? 'badge-success' : 
                      animal.estado === 'vendido' ? 'badge-warning' : 'badge-danger'
                    }`}>
                      {animal.estado === 'activo' ? '✅ Activo' : 
                       animal.estado === 'vendido' ? '💰 Vendido' : '❌ ' + animal.estado}
                    </span>
                  </td>
                  <td>{animal.raza_nombre || '-'}</td>
                  <td>{animal.ubicacion_nombre || '-'}</td>
                  <td>{animal.fecha_nacimiento ? new Date(animal.fecha_nacimiento).toLocaleDateString() : '-'}</td>
                  <td>
                    <div style={{ display: 'flex', gap: '5px', flexWrap: 'wrap' }}>
                      <button 
                        className="btn btn-info btn-sm"
                        onClick={() => handleView(animal.id)}
                        title="Ver detalles"
                      >
                        👁️
                      </button>
                      <button 
                        className="btn btn-warning btn-sm"
                        onClick={() => handleEdit(animal.id)}
                        title="Editar"
                      >
                        ✏️
                      </button>
                      <button 
                        className="btn btn-danger btn-sm"
                        onClick={() => handleDelete(animal.id)}
                        title="Eliminar"
                      >
                        🗑️
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
            </table>
          </div>
        ) : (
          <div className="empty-state">
            <div className="empty-state-icon">🐷</div>
            <h3>No hay animales registrados</h3>
            <p>Comienza registrando tu primer animal en el sistema</p>
            <button className="btn btn-primary" onClick={() => setShowForm(true)}>
              ➕ Registrar Primer Animal
            </button>
          </div>
        )}
      </div>

      {/* Modal de detalles */}
      {showDetail && animalDetail && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0,0,0,0.5)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 1000
        }}>
          <div className="card" style={{ width: '90%', maxWidth: '600px', margin: 0 }}>
            <div className="card-header">
              <h3 className="card-title">🐷 Detalles del Animal</h3>
              <button 
                className="btn btn-secondary btn-sm"
                onClick={() => setShowDetail(null)}
              >
                ❌
              </button>
            </div>
            <div className="grid grid-2">
              <div>
                <strong>ID:</strong> {animalDetail.identificador_unico}
              </div>
              <div>
                <strong>Nombre:</strong> {animalDetail.nombre || 'Sin nombre'}
              </div>
              <div>
                <strong>Sexo:</strong> {animalDetail.sexo}
              </div>
              <div>
                <strong>Categoría:</strong> {animalDetail.categoria}
              </div>
              <div>
                <strong>Estado:</strong> {animalDetail.estado}
              </div>
              <div>
                <strong>Raza:</strong> {animalDetail.raza_nombre || 'No especificada'}
              </div>
              <div>
                <strong>Fecha Nacimiento:</strong> {animalDetail.fecha_nacimiento ? new Date(animalDetail.fecha_nacimiento).toLocaleDateString() : 'No especificada'}
              </div>
              <div>
                <strong>Peso Nacimiento:</strong> {animalDetail.peso_nacimiento ? `${animalDetail.peso_nacimiento} kg` : 'No registrado'}
              </div>
              <div>
                <strong>Ubicación:</strong> {animalDetail.ubicacion_nombre || 'No asignada'}
              </div>
            </div>
            {animalDetail.observaciones && (
              <div style={{ marginTop: '15px' }}>
                <strong>Observaciones:</strong>
                <p style={{ marginTop: '5px', padding: '10px', backgroundColor: '#f8f9fa', borderRadius: '4px' }}>
                  {animalDetail.observaciones}
                </p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Animals;
